mapper.select:
	select  t.id,t.name as uname, t.real_name as name, t.unitid, t.depid, t.roleid
      		from teacher t 
      		where t.roleid!='1' and t.state=1

				and t.unitid = #{unitid,jdbcType=VARCHAR}


				and t.roleid = #{roleid,jdbcType=VARCHAR}


				and (t.real_name like '%'||#{uname}||'%' or t.name like '%'||#{uname}||'%')

	select  count(t.id)
      		from teacher t 
      		where t.roleid!='1' and t.state=1

				and t.unitid = #{unitid,jdbcType=VARCHAR}


				and t.roleid = #{roleid,jdbcType=VARCHAR}


				and (t.real_name like '%'||#{uname}||'%' or t.name like '%'||#{uname}||'%')

select distinct tp.tid,tp.pid from teacher_paper tp,teacher t  
where t.roleid!='1'
and t.id=tp.tid and tp.pid in (n'31',n'33',n'34',n'37') and tp.eid=#{eid,jdbcType=VARCHAR}

WITH tids AS (
	SELECT tp.tid FROM teacher_paper tp
	WHERE tp.eid = #{eid,jdbcType=VARCHAR} AND tp.pid = n'37'
	UNION
	SELECT tq.tid FROM teacher_question tq WHERE tq.eid = #{eid,jdbcType=VARCHAR}
	UNION
	SELECT tsc.tid FROM teacher_scorereview tsc WHERE tsc.eid = #{eid,jdbcType=VARCHAR}
)
SELECT t.id AS tid, t.real_name AS name, t.name AS username FROM tids d
JOIN teacher t ON t.id = d.tid WHERE t.roleid != '1'

        select count(*) as num
		  from teacher_paper tp
		 where tp.tid = #{tid,jdbcType=VARCHAR}
		   and tp.eid = #{eid,jdbcType=VARCHAR}
		   and tp.pid in

		   #{item,jdbcType=VARCHAR}

