mapper.select:
select ei.id, ei.ename, ei.cid, ei.cname, ei.code, ei.begindate, ei.enddate, ei.teacherid, ei.scount, t.real_name as teachername, t.name as username, ei.bid, ei.state, ei.subjectsum, ei.aorb, ei.mobile, ei.random, et.name as tyname, ei.passstate from examinfo ei left join teacher t on ei.teacherid=t.id left join examtype et on ei.type=et.id where ei.state != -1
and exists (select * from exampaper_course ec where ei.id = ec.eid and ec.cid in (select distinct tp.cid from teacher_permission tp where exists (select * from teacher t where tp.tid = t.id and t.unitid = #{unitid}) and tp.pid in (n'11', n'10')))
and ei.state = #{state}
and ei.mobile = 1
and (ei.mobile =0 or ei.mobile=2)
and ei.aorb = #{aorb}
and ei.term = #{term}
and ei.type = #{examType}
and ei.schoolyear = #{schoolYear}
and to_date(#{beginDate},'yyyy-MM-dd') <= trunc(ei.enddate) and to_date(#{endDate},'yyyy-MM-dd') >= trunc(ei.enddate)
and ei.id in (select eo.eid from examobject eo where 1 = 1
and eo.grade in #{gid}
and eo.specialtyid in #{sid}
)
and ei.id in (select ec.eid from course c,exampaper_course ec where ec.cid=c.id and c.unitid in #{unid})
and ei.id in (select ec.eid from exampaper_course ec where ec.cid=#{cid})
and ei.teacherid=#{teacherid}
and ei.begindate >= trunc(sysdate - #{limitDay})
and (ei.id like '%'||#{num}||'%' or ei.ename like '%'||#{num}||'%')
and (
ei.id like '%' || #{num} || '%'
)
and ei.id = #{rnum}
and (t.name like '%'||#{teacher}||'%' or t.real_name like '%'||#{teacher}||'%')
order by ei.begindate desc
order by ei.id
order by ei.scount
order by nlssort(t.real_name,'NLS_SORT=SCHINESE_PINYIN_M')
order by ei.state
order by ei.begindate
order by nlssort(ei.ename,'NLS_SORT=SCHINESE_PINYIN_M')
order by ei.cname
order by ei.enddate
desc
asc

